#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b, int* x, int* y) {
    if (a == 0) {
        *x = 0;
        *y = 1;
        return b;
    }

    int x1, y1;
    int g = gcd(b % a, a, &x1, &y1);
    *x = y1 - (b / a) * x1;
    *y = x1;
    return g;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, X, Y;
        scanf("%d %d %d %d", &N, &M, &X, &Y);
        int g = gcd(X, Y, &x, &y);
        if (N % g != M % g) {
            printf("Pofik\n");
        } else {
            int a = (N - M) / g;
            if (a >= 0 && a <= 111) {
                printf("Chefirnemo\n");
            } else {
                printf("Pofik\n");
            }
        }
    }
    return 0;
}

