                System.out.println("Pofik");
            } else {
                int a = (N - M) / g;
                if (a >= 0 && a <= 111) {
                    System.out.println("Chefirnemo");
                } else {
                    System.out.println("Pofik");
                }
            }
        }
    }

    public static int gcd(int a, int b) {
        if (a == 0)
            return b;
        return gcd(b % a, a);
    }
}

